
CREATE TABLE public.blog_posts (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  slug TEXT NOT NULL UNIQUE,
  title TEXT NOT NULL,
  excerpt TEXT,
  content TEXT NOT NULL,
  published BOOLEAN NOT NULL DEFAULT true,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
GRANT SELECT ON public.blog_posts TO anon, authenticated;
GRANT ALL ON public.blog_posts TO service_role;
ALTER TABLE public.blog_posts ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Anyone can read published posts" ON public.blog_posts FOR SELECT USING (published = true);

CREATE TABLE public.blog_comments (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  post_id UUID NOT NULL REFERENCES public.blog_posts(id) ON DELETE CASCADE,
  author_name TEXT NOT NULL,
  message TEXT NOT NULL,
  approved BOOLEAN NOT NULL DEFAULT true,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
GRANT SELECT, INSERT ON public.blog_comments TO anon, authenticated;
GRANT ALL ON public.blog_comments TO service_role;
ALTER TABLE public.blog_comments ENABLE ROW LEVEL SECURITY;
CREATE POLICY "Anyone can read approved comments" ON public.blog_comments FOR SELECT USING (approved = true);
CREATE POLICY "Anyone can post a comment" ON public.blog_comments FOR INSERT WITH CHECK (
  char_length(author_name) BETWEEN 1 AND 80 AND char_length(message) BETWEEN 1 AND 2000
);

INSERT INTO public.blog_posts (slug, title, excerpt, content) VALUES (
  'dissociation-traumatique-reconnexion',
  'Dissociation traumatique et reconnexion à soi : retrouver son unité intérieure',
  'La dissociation traumatique est un mécanisme naturel de protection. Découvrez comment retrouver progressivement votre unité intérieure grâce à la kinésiologie, aux approches corporelles et énergétiques.',
  E'## Qu''est-ce que la dissociation traumatique ?\n\nLa dissociation traumatique est un mécanisme naturel de protection mis en place par le cerveau et le système nerveux lorsqu''une personne vit une expérience perçue comme trop intense, douloureuse ou menaçante. Face à un traumatisme, qu''il soit physique, émotionnel ou psychologique, il arrive que l''organisme ne puisse ni fuir ni combattre. Il entre alors dans un état de survie.\n\nDans cet état, certaines émotions, sensations corporelles ou souvenirs peuvent être mis à distance de la conscience afin de réduire la souffrance immédiate. Cette capacité permet de traverser des événements extrêmement difficiles, mais lorsqu''elle persiste dans le temps, elle peut entraîner un sentiment de déconnexion de soi-même.\n\nCertaines personnes décrivent l''impression d''être spectatrices de leur vie, de ne plus ressentir pleinement leurs émotions ou d''avoir perdu le contact avec une partie d''elles-mêmes.\n\n## Les signes d''une dissociation traumatique\n\n- Difficulté à ressentir ses émotions.\n- Sensation d''être coupé de son corps.\n- Impression d''être absent ou dans le brouillard.\n- Troubles de la mémoire concernant certains événements.\n- Difficulté à savoir ce que l''on ressent réellement.\n- Fatigue chronique ou manque d''énergie.\n- Sentiment de vide intérieur.\n- Difficulté à être pleinement présent dans l''instant.\n\nCes manifestations ne signifient pas qu''une personne est "cassée" ou incapable de guérir. Elles représentent souvent une adaptation intelligente du système nerveux face à des expériences passées.\n\n## Quand la survie devient une prison intérieure\n\nCe qui était autrefois une protection peut parfois devenir un obstacle à l''épanouissement.\n\nLorsque certaines émotions restent bloquées ou que certaines expériences n''ont jamais pu être intégrées, une partie de notre énergie reste mobilisée pour maintenir cette séparation intérieure.\n\nNous pouvons alors avoir l''impression de vivre en mode automatique, de répéter certains schémas ou de ne pas parvenir à accéder pleinement à notre potentiel.\n\nLa dissociation peut également limiter notre capacité à ressentir la joie, l''amour, l''inspiration ou la connexion profonde avec nous-mêmes.\n\n## La reconnexion à soi : un chemin de guérison\n\nLa guérison ne consiste généralement pas à revivre les traumatismes, mais à retrouver progressivement un sentiment de sécurité intérieure permettant au système nerveux de se réorganiser.\n\nLa reconnexion à soi est un processus qui invite à revenir doucement vers :\n\n- Ses sensations corporelles.\n- Ses émotions.\n- Ses besoins profonds.\n- Son intuition.\n- Sa présence intérieure.\n\nChaque personne avance à son rythme. Il ne s''agit pas de forcer une ouverture émotionnelle, mais de permettre un retour progressif à l''unité intérieure.\n\n## Le rôle du corps dans la guérison\n\nLes traumatismes ne sont pas uniquement enregistrés dans la mémoire consciente. Ils peuvent également laisser une empreinte dans le système nerveux et dans le corps.\n\nC''est pourquoi les approches corporelles peuvent être particulièrement intéressantes dans un processus de reconnexion à soi.\n\nLe mouvement, la respiration consciente, la méditation, certaines pratiques énergétiques et la kinésiologie peuvent contribuer à restaurer un sentiment de sécurité et de présence.\n\nLorsque le corps se sent en sécurité, il devient plus facile d''accéder à ses ressources naturelles de guérison.\n\n## Kinésiologie et libération émotionnelle\n\nLa kinésiologie est une approche qui s''intéresse aux liens entre le corps, les émotions et le fonctionnement global de la personne.\n\nGrâce au test musculaire et à différents outils d''accompagnement, elle peut permettre d''identifier certains stress ou déséquilibres qui influencent encore le présent.\n\nL''objectif n''est pas de revivre les événements difficiles, mais d''aider l''organisme à retrouver ses capacités naturelles d''adaptation et d''équilibre.\n\nDe nombreuses personnes rapportent un sentiment d''apaisement, une meilleure compréhension d''elles-mêmes et une plus grande fluidité émotionnelle après ce type d''accompagnement.\n\n## Les approches énergétiques et la reconnexion intérieure\n\nDans les traditions énergétiques et spirituelles, certaines formes de dissociation sont parfois décrites comme une perte de connexion avec certaines dimensions de soi.\n\nDes pratiques telles que la méditation, les soins énergétiques, le travail sur les chakras ou certaines approches de recouvrement symbolique peuvent être utilisées comme des outils de reconnexion intérieure.\n\nCes approches ne remplacent pas un accompagnement médical ou psychologique lorsque celui-ci est nécessaire, mais peuvent constituer un complément intéressant dans une démarche globale de mieux-être.\n\n## L''éveil de la conscience et le retour à soi\n\nSur le chemin du développement personnel et spirituel, il est fréquent que certaines blessures ou zones de déconnexion deviennent plus visibles.\n\nCela peut parfois être déstabilisant, mais représente également une opportunité de transformation.\n\nLa véritable évolution ne consiste pas à fuir ses blessures, mais à les accueillir avec bienveillance afin de retrouver progressivement son unité intérieure.\n\nChaque pas vers plus de présence, plus de conscience et plus d''amour de soi participe à ce processus de reconnexion.\n\n## Conclusion\n\nLa dissociation traumatique est avant tout un mécanisme de protection. Elle témoigne de la capacité remarquable du système nerveux à préserver l''intégrité de la personne face à des expériences difficiles.\n\nLa bonne nouvelle est que la reconnexion à soi est possible. Grâce à un accompagnement adapté, à la kinésiologie, aux approches corporelles, énergétiques et à un travail progressif de réappropriation de son vécu, il est possible de retrouver davantage de présence, de vitalité et d''harmonie intérieure.\n\nLe chemin de guérison est unique pour chacun, mais il mène souvent vers une découverte essentielle : celle de notre capacité profonde à retrouver notre véritable nature.'
);
